document.addEventListener("DOMContentLoaded",function(){let e=document.getElementById("hamburger-menu"),t=document.getElementById("preferences-content");if(e&&t){e.addEventListener("click",function(){e.classList.toggle("active"),t.classList.toggle("active")});let c=t.querySelectorAll("a");c.forEach(c=>{c.addEventListener("click",function(){e.classList.remove("active"),t.classList.remove("active")})}),document.addEventListener("click",function(c){c.target.closest(".preferences")||(e.classList.remove("active"),t.classList.remove("active"))})}});